import React, { Component } from "react";
import Button from "../button/Button";
import AppConfig, { IGreeting } from "../../globals/appConfig";
import emoji from 'react-easy-emoji';

import './Greeting.scss';

type GreetingProps = typeof Greeting.defaultProps & {
    data: IGreeting;
};

export default class Greeting extends Component<GreetingProps> {
    static defaultProps = {
        data: AppConfig.GREETING
    };

    render() {
        return (
            <div className="greetingContainer" id="greeting">
                <div className="greetingMain">
                    <div className="greetingMainTextContainer">
                        <h1 className="greetingMainText">
                            {" "}
                            {this.props.data.title}
                            {" "}
                            <span className="greetingWaveEmoji">{emoji("👋")}</span>
                        </h1>
                        <p className="greetingLongText">{this.props.data.subTitle}</p>
                        <div className="greetingButton">
                            <Button text="Contact me" class="" newTab={false} href="https://indramahkota.info" />
                        </div>
                    </div>
                    <div className="greetingImageContainer">
                        <img alt="Man sitting on table" src={require("../../../assets/images/manOnTable.svg")}></img>
                    </div>
                </div>
            </div>
        );
    }
}