import React, { Component } from "react";

import './Button.scss';

interface ButtonProps {
    text: string;
    class: string;
    href: string;
    newTab: boolean;
}

export default class Button extends Component<ButtonProps> {
    render() {
        return (
            <div className={this.props.class}>
                <a className="mainButton" href={this.props.href} target={this.props.newTab ? "_blank" : ''} rel="noopener noreferrer">
                    {this.props.text}
                </a>
            </div>
        );
    }
}